using namespace std;
class Solution {
    public:
    int longestRepeatingCharacterReplacement(string data, int k) {
        int maxLength = 0;
        int n = data.size();
        for (int start = 0; start < n; ++start) {
            unordered_map<char, int> countMap;
            int maxCount = 0;
            for (int end = start; end < n; ++end) {
                countMap[data[end]]++;
                maxCount = max(maxCount, countMap[data[end]]);
                int currentLength = end - start + 1;
                if (currentLength - maxCount <= k) {
                    maxLength = max(maxLength, currentLength);
                }
            }
        }
        return maxLength;
    }
}
