func longestRepeatingCharacterReplacement(data string, k int) int {
    maxLength := 0
    n := len(data)

    for i := 0; i < n; i++ {
        for j := i; j < n; j++ {
            substr := data[i : j+1]
            count := make(map[rune]int)
            maxCount := 0

            for _, char := range substr {
                count[char]++
                if count[char] > maxCount {
                    maxCount = count[char]
                }
            }

            if (j-i+1)-maxCount <= k {
                if maxLength < (j-i+1) {
                    maxLength = j - i + 1
                }
            }
        }
    }
    return maxLength
}

